// ============================================================
//  Supabase Edge Function: gerar-ata-docx
//  Preenche o template .docx da ata com substituições literais exatas
//  Deploy: supabase functions deploy gerar-ata-docx --no-verify-jwt
// ============================================================

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import JSZip from "https://esm.sh/jszip@3.10.1";

const CORS = {
  "Access-Control-Allow-Origin":  "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
};

function esc(s: string): string {
  return String(s || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function paraLista(texto: string, numId = "1", ilvl = "0"): string {
  const left = ilvl === "0" ? "720" : "1440";
  return `<w:p><w:pPr><w:numPr><w:ilvl w:val="${ilvl}"/><w:numId w:val="${numId}"/></w:numPr>`
    + `<w:spacing w:after="200" w:line="276" w:lineRule="auto"/>`
    + `<w:ind w:left="${left}" w:hanging="360"/>`
    + `<w:rPr><w:color w:val="242424"/></w:rPr></w:pPr>`
    + `<w:r><w:rPr><w:color w:val="242424"/></w:rPr>`
    + `<w:t xml:space="preserve">${esc(texto)}</w:t></w:r></w:p>`;
}

function linhaPendencia(p: Record<string,string>, idx: number): string {
  const fill = idx % 2 === 0 ? "f3f3f3" : "ffffff";
  const cel = (v: string) =>
    `<w:tc><w:tcPr><w:shd w:fill="${fill}" w:val="clear"/></w:tcPr>`
    + `<w:p><w:pPr><w:spacing w:after="200" w:line="276" w:lineRule="auto"/>`
    + `<w:rPr><w:color w:val="242424"/></w:rPr></w:pPr>`
    + `<w:r><w:rPr><w:color w:val="242424"/></w:rPr>`
    + `<w:t xml:space="preserve">${esc(v)}</w:t></w:r></w:p></w:tc>`;
  return `<w:tr><w:trPr><w:cantSplit w:val="0"/></w:trPr>`
    + cel(p.atividade||"") + cel(p.responsavel||"") + cel(p.prazo||"") + cel(p.status||"Pendente")
    + `</w:tr>`;
}

// ── Placeholders exatos extraídos do template ────────────────────

const PARA_0B = "<w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"0000000B\"><w:pPr><w:numPr><w:ilvl w:val=\"1\"/><w:numId w:val=\"1\"/></w:numPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:ind w:left=\"1440\" w:hanging=\"360\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/><w:u w:val=\"none\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p>";  // parágrafo vazio após status (topicos vão antes)
const PARA_0D = "<w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"0000000D\"><w:pPr><w:numPr><w:ilvl w:val=\"1\"/><w:numId w:val=\"1\"/></w:numPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:ind w:left=\"1440\" w:hanging=\"360\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p>";  // parágrafo vazio decisões
const PARA_18 = "<w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"00000018\"><w:pPr><w:numPr><w:ilvl w:val=\"0\"/><w:numId w:val=\"2\"/></w:numPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:ind w:left=\"720\" w:hanging=\"360\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/><w:u w:val=\"none\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p>";  // parágrafo vazio riscos
const PARA_1A = "<w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"0000001A\"><w:pPr><w:numPr><w:ilvl w:val=\"0\"/><w:numId w:val=\"3\"/></w:numPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:ind w:left=\"720\" w:hanging=\"360\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/><w:u w:val=\"none\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p>";  // parágrafo vazio próximos passos
const EMPTY_ROW = "<w:tr><w:trPr><w:cantSplit w:val=\"0\"/><w:trHeight w:val=\"620.2343750000001\" w:hRule=\"atLeast\"/><w:tblHeader w:val=\"0\"/></w:trPr><w:tc><w:tcPr><w:shd w:fill=\"f3f3f3\" w:val=\"clear\"/></w:tcPr><w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"00000013\"><w:pPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p></w:tc><w:tc><w:tcPr><w:shd w:fill=\"f3f3f3\" w:val=\"clear\"/></w:tcPr><w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"00000014\"><w:pPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p></w:tc><w:tc><w:tcPr><w:shd w:fill=\"f3f3f3\" w:val=\"clear\"/></w:tcPr><w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"00000015\"><w:pPr><w:spacing w:after=\"200\" w:line=\"276\" w:lineRule=\"auto\"/><w:jc w:val=\"left\"/><w:rPr><w:color w:val=\"242424\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p></w:tc><w:tc><w:tcPr><w:shd w:fill=\"f3f3f3\" w:val=\"clear\"/></w:tcPr><w:p w:rsidR=\"00000000\" w:rsidDel=\"00000000\" w:rsidP=\"00000000\" w:rsidRDefault=\"00000000\" w:rsidRPr=\"00000000\" w14:paraId=\"00000016\"><w:pPr><w:keepNext w:val=\"0\"/><w:keepLines w:val=\"0\"/><w:widowControl w:val=\"1\"/><w:pBdr><w:top w:space=\"0\" w:sz=\"0\" w:val=\"nil\"/><w:left w:space=\"0\" w:sz=\"0\" w:val=\"nil\"/><w:bottom w:space=\"0\" w:sz=\"0\" w:val=\"nil\"/><w:right w:space=\"0\" w:sz=\"0\" w:val=\"nil\"/><w:between w:space=\"0\" w:sz=\"0\" w:val=\"nil\"/></w:pBdr><w:shd w:fill=\"auto\" w:val=\"clear\"/><w:spacing w:after=\"200\" w:before=\"0\" w:line=\"276\" w:lineRule=\"auto\"/><w:ind w:left=\"0\" w:right=\"0\" w:firstLine=\"0\"/><w:jc w:val=\"left\"/><w:rPr><w:rFonts w:ascii=\"Cambria\" w:cs=\"Cambria\" w:eastAsia=\"Cambria\" w:hAnsi=\"Cambria\"/><w:b w:val=\"1\"/><w:bCs w:val=\"1\"/><w:color w:val=\"000000\"/><w:sz w:val=\"22\"/><w:szCs w:val=\"22\"/></w:rPr></w:pPr><w:r w:rsidDel=\"00000000\" w:rsidR=\"00000000\" w:rsidRPr=\"00000000\"><w:rPr><w:rtl w:val=\"0\"/></w:rPr></w:r></w:p></w:tc></w:tr>";  // linha vazia tabela pendências
const TEMPLATE_B64 = "";

function preencherXml(xml: string, d: Record<string, unknown>): string {
  const get = (k: string) => String((d[k] as string) || "");
  const arr = (k: string): string[] => (d[k] as string[]) || [];
  const pends = (d["pendencias"] as Record<string,string>[]) || [];

  // Campos simples — substituição literal exata
  xml = xml.replace("Projeto /Cliente:  [nome do cliente]", `Projeto / Cliente:  ${esc(get("cliente"))}`);
  xml = xml.replace("Consultor :  [nome do consultor]",     `Consultor:  ${esc(get("consultor"))}`);
  xml = xml.replace("Data: dd/mm/yy",                       `Data: ${esc(get("data"))}`);
  xml = xml.replace("Participantes: </w:t>",                `Participantes: ${esc(get("participantes"))}</w:t>`);
  xml = xml.replace("Status do projeto:  </w:t>",           `Status do projeto: ${esc(get("status_projeto"))}</w:t>`);

  // Tópicos — inserir antes do paraId 0000000B
  const topicosXml = arr("topicos").length
    ? arr("topicos").map(t => paraLista(t, "1", "0")).join("")
    : "";
  xml = xml.replace(PARA_0B, topicosXml + PARA_0B);

  // Decisões — substituir parágrafo vazio 0000000D
  const decisoesXml = arr("decisoes").length
    ? arr("decisoes").map(d2 => paraLista(d2, "1", "1")).join("")
    : paraLista("—", "1", "1");
  xml = xml.replace(PARA_0D, decisoesXml);

  // Pendências — substituir linha vazia da tabela
  const linhasXml = pends.length
    ? pends.map((p, i) => linhaPendencia(p, i)).join("")
    : linhaPendencia({ atividade:"—", responsavel:"—", prazo:"—", status:"—" }, 0);
  xml = xml.replace(EMPTY_ROW, linhasXml);

  // Riscos — substituir parágrafo vazio 00000018
  const riscosXml = arr("riscos").length
    ? arr("riscos").map(r => paraLista(r, "2", "0")).join("")
    : paraLista("Nenhum risco identificado.", "2", "0");
  xml = xml.replace(PARA_18, riscosXml);

  // Próximos passos — substituir parágrafo vazio 0000001A
  const passosXml = arr("proximos_passos").length
    ? arr("proximos_passos").map(p2 => paraLista(p2, "3", "0")).join("")
    : paraLista("—", "3", "0");
  xml = xml.replace(PARA_1A, passosXml);

  return xml;
}

serve(async (req: Request) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: CORS });

  try {
    const { dados } = await req.json();
    if (!dados) throw new Error("Campo 'dados' obrigatório.");

    // Decode template embutido
    const templateBytes = Uint8Array.from(atob(TEMPLATE_B64), c => c.charCodeAt(0));
    const zip = await JSZip.loadAsync(templateBytes);

    // Preenche o document.xml
    const docXml = await zip.file("word/document.xml")!.async("string");
    const docXmlPreenchido = preencherXml(docXml, dados);
    zip.file("word/document.xml", docXmlPreenchido);

    // Gera o novo docx
    const docxBytes = await zip.generateAsync({
      type: "uint8array",
      compression: "DEFLATE",
      compressionOptions: { level: 6 },
    });

    // ── Converte para PDF via CloudConvert ──────────────────────────
    const CLOUDCONVERT_KEY = Deno.env.get("CLOUDCONVERT_API_KEY");
    if (!CLOUDCONVERT_KEY) throw new Error("CLOUDCONVERT_API_KEY não configurada nos secrets.");

    // 1. Cria o job de conversão
    const jobRes = await fetch("https://api.cloudconvert.com/v2/jobs", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${CLOUDCONVERT_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        tasks: {
          "upload-docx": {
            operation: "import/upload",
          },
          "convert-to-pdf": {
            operation: "convert",
            input: "upload-docx",
            input_format: "docx",
            output_format: "pdf",
            engine: "libreoffice",
          },
          "export-pdf": {
            operation: "export/url",
            input: "convert-to-pdf",
          },
        },
      }),
    });
    if (!jobRes.ok) throw new Error(`CloudConvert job error: ${await jobRes.text()}`);
    const job = await jobRes.json();

    // 2. Faz upload do .docx
    const uploadTask = job.data.tasks.find((t: {name: string}) => t.name === "upload-docx");
    const uploadUrl = uploadTask.result?.form?.url || uploadTask.result?.url;
    if (!uploadUrl) throw new Error("CloudConvert: URL de upload não encontrada.");

    const formData = new FormData();
    if (uploadTask.result?.form?.parameters) {
      for (const [k, v] of Object.entries(uploadTask.result.form.parameters)) {
        formData.append(k, v as string);
      }
    }
    formData.append("file", new Blob([docxBytes], { type: "application/vnd.openxmlformats-officedocument.wordprocessingml.document" }), "ata.docx");

    const upRes = await fetch(uploadUrl, { method: "POST", body: formData });
    if (!upRes.ok) throw new Error(`CloudConvert upload error: ${await upRes.text()}`);

    // 3. Aguarda a conclusão do job (polling)
    let pdfUrl = "";
    for (let i = 0; i < 30; i++) {
      await new Promise(r => setTimeout(r, 2000));
      const statusRes = await fetch(`https://api.cloudconvert.com/v2/jobs/${job.data.id}`, {
        headers: { "Authorization": `Bearer ${CLOUDCONVERT_KEY}` },
      });
      const status = await statusRes.json();
      const exportTask = status.data.tasks.find((t: {name: string}) => t.name === "export-pdf");
      if (exportTask?.status === "finished" && exportTask?.result?.files?.[0]?.url) {
        pdfUrl = exportTask.result.files[0].url;
        break;
      }
      if (status.data.status === "error") throw new Error("CloudConvert: erro na conversão.");
    }
    if (!pdfUrl) throw new Error("CloudConvert: timeout aguardando PDF.");

    // 4. Baixa o PDF
    const pdfRes = await fetch(pdfUrl);
    if (!pdfRes.ok) throw new Error("CloudConvert: erro ao baixar o PDF.");
    const pdfBytes = new Uint8Array(await pdfRes.arrayBuffer());

    return new Response(pdfBytes, {
      status: 200,
      headers: {
        ...CORS,
        "Content-Type": "application/pdf",
        "Content-Disposition": `attachment; filename="ata.pdf"`,
      },
    });

  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    return new Response(JSON.stringify({ error: message }), {
      status: 500,
      headers: { ...CORS, "Content-Type": "application/json" },
    });
  }
});
